/// <summary>
/// The data contract for a <c>ETGCustPaymPostedBusinessEventContract</c>.
/// </summary>
[DataContract]
public class ETGCustPaymPostedBusinessEventContract extends BusinessEventsContract
{
    private CustAccount                 paymentAccount;
    private PaymId                      paymentId;
    private PaymReference               paymentReference;
    private DateTimeIso8601             paymentDate;
    private PaymMode                    paymentMethod;
    private SelectableDataArea          legalEntity;
    private CurrencyCode                currencyCode;
    private InvoiceId                   invoiceId;
    private DateTimeIso8601             dueDate;
    private LedgerJournalName           journalName;
    private LineAmount                  paymentAmount;
    private String10                    isFinalPayment;

}

