/// <summary>
/// Creates a <c>ETGCustPaymPostedBusinessEventContract</c> from a <c>LedgerJournalTrans</c> record.
/// </summary>
/// <param name = "_ledgerJournalTrans">A <c>ETGCustPaymIntegrationHistory</c> record.</param>
/// <returns>A <c>ETGCustPaymPostedBusinessEventContract</c>.</returns>
public static ETGCustPaymPostedBusinessEventContract newFromLedgerJournalTrans(ETGCustPaymIntegrationHistory _custPaymIntegrationHistory)
{
    var contract = new ETGCustPaymPostedBusinessEventContract();
    contract.initialize(_custPaymIntegrationHistory);
    return contract;
}

private void initialize(ETGCustPaymIntegrationHistory custPaymIntegrationHistory)
{
    paymentId         = custPaymIntegrationHistory.JournalNum;
    paymentReference  = custPaymIntegrationHistory.Accounting_System_Payment_Id;
    paymentDate       = custPaymIntegrationHistory.TransDate;
    paymentAmount     = custPaymIntegrationHistory.Allocated_Amount;
    paymentMethod     = custPaymIntegrationHistory.PaymMode;
    legalEntity       = custPaymIntegrationHistory.DataAreaId;
    currencyCode      = custPaymIntegrationHistory.CurrencyCode;
    dueDate           = custPaymIntegrationHistory.Due;
    invoiceId         = custPaymIntegrationHistory.Invoice_Master_Id;
    isFinalPayment    = custPaymIntegrationHistory.IsFinalPayment;
}

[DataMember('PaymentAccount'), BusinessEventsDataMember("@AccountsReceivable:PaymentAccount")]
public CustAccount parmPaymentAccount(CustAccount _paymentAccount = paymentAccount)
